// Nimm den Text-Output vom vorherigen KI-Knoten
const aiOutput = $input.first().json.output;

// Wir ersetzen die Zeichenfolge "\\n" durch einen echten Zeilenumbruch
const cleanOutput = aiOutput.replace(/\\n/g, '\n');

// Extrahiere die einzelnen Teile durch Splitting
const titlePart = cleanOutput.split('Tags:')[0];
const tagsPart = cleanOutput.split('DescriptionHashtags:')[0].split('Tags:')[1];
const hashtagsPart = cleanOutput.split('DescriptionHashtags:')[1];

// Bereinige die extrahierten Teile und erstelle das initiale Objekt
const result = {
  title: titlePart ? titlePart.replace('Title:', '').trim() : 'Default Title',
  tags: tagsPart ? tagsPart.trim() : 'Default, Tags',
  descriptionHashtags: hashtagsPart ? hashtagsPart.trim() : '#default'
};

// --- FINALE BEREINIGUNG: KÜRZEN, FORMATIEREN & SÄUBERN ---
const YOUTUBE_TAG_LIMIT = 500;
let finalTags = [];
let currentLength = 0;
const allTags = result.tags.split(',');

for (const tag of allTags) {
  // Entferne alle verbotenen '#'-Zeichen aus dem Tag
  const sanitizedTag = tag.trim().replace(/#/g, '');
  if (sanitizedTag === "") continue;

  // Prüfe, ob das Hinzufügen des nächsten Tags (plus Komma) das Limit sprengen würde
  // Korrektur: Wir rechnen +1 (nur für das Komma), nicht +2
  if (currentLength + sanitizedTag.length + 1 <= YOUTUBE_TAG_LIMIT) {
    finalTags.push(sanitizedTag);
    // Addiere die Länge des Tags + 1 (für das Komma)
    currentLength += sanitizedTag.length + 1;
  } else {
    break;
  }
}

// Fügt das Array zu einem einzigen String zusammen, OHNE Leerzeichen
result.tags = finalTags.join(',');

// Gib die sauberen Daten an den nächsten Knoten weiter
return [{ json: result }];
